def to_b64(image_bytes, mime="image/jpeg"):
    return f"data:{mime};base64,{base64.b64encode(image_bytes).decode()}"


# ──────────────────────────────────────────────────────────
# WAVESPEED HELPERS
# ──────────────────────────────────────────────────────────
def ws_submit(endpoint, payload):
    _base = WS_API if WS_API.startswith("http") else "https://api.wavespeed.ai/api/v3"
    r = requests.post(
        f"{_base}/{endpoint}",
        headers={"Authorization": f"Bearer {WS_KEY}", "Content-Type": "application/json"},
        json=payload,
        timeout=30,
    )
    if r.status_code == 401:
        raise RuntimeError(f"Wavespeed 401 Unauthorized — το API key είναι λάθος ή έχει λήξει. Έλεγξε το key στο sidebar.\nResponse: {r.text[:300]}")
    if not r.ok:
        raise RuntimeError(f"Wavespeed {r.status_code}: {r.text[:300]}")
    data = r.json()
    pred_id = data.get("data", {}).get("id")
    if not pred_id:
        raise RuntimeError(f"Wavespeed: {data}")
    return pred_id


def ws_poll(pred_id, progress_bar):
    _base = WS_API if WS_API.startswith("http") else "https://api.wavespeed.ai/api/v3"
    max_iter = 150  # 150 × 4s = 10 min max
    for i in range(max_iter):
        time.sleep(4)
        r = requests.get(
            f"{_base}/predictions/{pred_id}/result",
            headers={"Authorization": f"Bearer {WS_KEY}"},
            timeout=30,
        )
        d = r.json().get("data", {})
        status = d.get("status", "running")
        # 0 → 90% linearly over ~4 min, then 100% on complete
        pct = min(0.9, (i + 1) / 60)
        progress_bar.progress(pct, text=f"⏳ {status}...")
        if status == "completed":
            progress_bar.progress(1.0, text="✅ Ολοκληρώθηκε!")
            outputs = d.get("outputs", [])
            return outputs[0] if outputs else None
        if status == "failed":
            raise RuntimeError(d.get("error", "Wavespeed generation failed"))
    raise TimeoutError("Wavespeed timeout (10 λεπτά)")


